INSERT INTO public.photos VALUES (21707, 'Casa Gavâ”œÂ¡n 1930', 'Foto Palacio. 1930. Imagen de la antigua "Casa Gavâ”œÂ¡n", esquinada entre la calle Palafox (derecha), y la calle Pedro Liâ”œâ–’â”œÃ­n (a la izquierda). Salvada de las obras de apertura de San Vicente de Paâ”œâ•‘l, por estar un poco alejada del epicentro del nuevo vial, varias dâ”œÂ®cadas despuâ”œÂ®s serâ”œÂ¡a piqueteada para construir encima una indescriptible edificaciâ”œâ”‚n de Telefâ”œâ”‚nica. Fuente visual: "Aragâ”œâ”‚n : revista grâ”œÃ­fica de cultura aragonesa" (Aâ”œâ–’o VI, Nâ”¬â•‘ 63, dic. 1930).', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65360900, -0.87406300, '0101000020E6100000C498F4F752F8EBBF86AFAF75A9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16012092932.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16012092932.webp', 'https://www.flickr.com/photos/zaragozaantigua/16012092932/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21790, 'Coso Bajo c.1934', 'Vista aâ”œÂ®rea del Coso bajo y sus alrededores. Arriba a la izquierda, el gran edificio de la Universidad de la Magdalena. A la derecha, el intrincado laberinto de la calle del Sepulcro, Pallaruelo, del Lobo, Monserrate, Conde de Alperche, Chantre... Fuente visual: www.facebook.com/photo.php?fbid=575487972606230&set=g...', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65335400, -0.87184100, '0101000020E610000061FBC9181FE6EBBFFB5A971AA1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24147192773.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24147192773.webp', 'https://www.flickr.com/photos/zaragozaantigua/24147192773/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21952, 'Calle Universidad 1949', 'Imagen de la calle Universidad capturada desde el tramo entre las calles Torrellas y Palafox, que es la primera calle que se abre a la izquierda. Al fondo, la calle Don Teobaldo, con leve vista del Convento de las Canonesas del Sto. Sepulcro. Inmediata, a la derecha, la calle Trinidad. La imagen se ha tomado justo al lado de los muros de la antigua Universidad Literaria de la Magdalena. Fuente visual: Juan Mora Insa, AMZ.', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65322600, -0.87285500, '0101000020E610000075CDE49B6DEEEBBFCD72D9E89CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19171108130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19171108130.webp', 'https://www.flickr.com/photos/zaragozaantigua/19171108130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21990, '&quot;CEFA&quot; Plaza de Asso, 1946', 'Imagen del interior de los originales talleres de Celulosa Fabril "CEFA", empresa fundada por Eduardo Blanchard Castillo en 1946, en el nâ”¬â•‘ 1 de la plaza de Asso, entre las calles del â”œÃ´rgano, y Torrellas. Allâ”œÂ¡ se acometâ”œÂ¡a la fabricaciâ”œâ”‚n de câ”œÃ­psulas de celulosa para tapones de botellas, y pronto comenzarâ”œÂ¡a la producciâ”œâ”‚n de gelatinas, sacarinas y jabones, y en 1952, el desarrollo de la inyecciâ”œâ”‚n de termoplâ”œÃ­sticos, que hizo de los juguetes una de las grandes seâ”œâ–’as de identidad de la empresa. A mediados de esa dâ”œÂ®cada, este espacio se habâ”œÂ¡a quedado muy pequeâ”œâ–’o, lo que derivâ”œâ”‚ en su traslado a una nueva y mucho mayor planta, en la calle de Miguel Servet. Fuente visual: "CEFA: una mirada al futuro 1946-2016", en Archivo Josâ”œÂ® Marâ”œÂ¡a Ballestâ”œÂ¡n Miguel.', 1946, 1946, 1946, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65294000, -0.87378700, '0101000020E61000003F70952710F6EBBF0820B58993D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30749184261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30749184261.webp', 'https://www.flickr.com/photos/zaragozaantigua/30749184261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22021, 'Calle de Josâ”œÂ® Palafox c.1940', 'Imagen del â”œâ•‘ltimo tramo de la calle de Josâ”œÂ® Palafox, donde destaca a la derecha, en el nâ”¬â•‘ 29, el Laboratorio Quâ”œÂ¡mico Municipal construido en 1914 con proyecto de Josâ”œÂ® de Yarza Echenique. Frente a â”œÂ®l, los antiguos inmuebles de los nâ”œâ•‘meros 28 y 30. Hacia el fondo, la calle se estrecha de forma notable hasta el cruce con la de Gavâ”œÂ¡n. La imagen estâ”œÃ­ realizada desde la esquina con la calle de la Universidad, a espaldas de la homâ”œâ”‚nima e histâ”œâ”‚rica instituciâ”œâ”‚n educativa, con un tancredo en primer tâ”œÂ®rmino ejerciendo de tal.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65324200, -0.87286500, '0101000020E610000058569A9482EEEBBFD32F116F9DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49898657137.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49898657137.webp', 'https://www.flickr.com/photos/zaragozaantigua/49898657137/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22036, 'Calle del â”œÃ´rgano c.1940', 'Grabado de Salvador Martâ”œÂ¡nez Blasco con una vista de la calle del â”œÃ´rgano y la iglesia de la Magdalena. A la derecha, casona de los Lanes de Villanueva, esquinera con la calle de Martâ”œÂ¡n Carrillo y derribada a principios de los aâ”œâ–’os 40. Su piedra armera con el escudo perdura en el Museo de Zaragoza.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65269700, -0.87387400, '0101000020E6100000FA635A9BC6F6EBBF429946938BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54413600082.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54413600082.webp', 'https://www.flickr.com/photos/zaragozaantigua/54413600082/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22110, 'Calle Mayor 1951', 'Imagen del â”œâ•‘ltimo tramo de la calle Mayor, paralelo a la iglesia parroquial de la Magdalena, casi ya en la plaza del mismo nombre. En el lateral del templo luce soleado, aâ”œâ•‘n, el antiguo bajorrelieve en forma de capilla, o figurado altar, dedicada a San Cristâ”œâ”‚bal de Licia, que ademâ”œÃ­s le daba nombre al arquitrabado "arco" bajo el que embocaba, justo enfrente, la calle de San Cristâ”œâ”‚bal, entre la "Farmacia" de la imagen (edificio luego derribado), y el abalconado nâ”¬â•‘ 60 de la calle Mayor (sobrevive). Esta tipologâ”œÂ¡a de "arcos" era prâ”œÃ­ctica comâ”œâ•‘n como forma de ganar espacio extra habitacional en zonas densamente edificadas de la ciudad antigua, dejando la altura suficiente para que pudiera transitar por debajo, sin problemas, una persona a lomos de caballerâ”œÂ¡a. Fuente visual: Juan Mora Insa, en AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22004534908.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22004534908.webp', 'https://www.flickr.com/photos/zaragozaantigua/22004534908/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22141, 'Calle de Gavâ”œÂ¡n 1951', 'Imagen de la calle de Gavâ”œÂ¡n, que fuera antiguo callizo de Domingo Vero, capturada en el tramo entre la plaza de Asso, y la calle de Palafox, al fondo destaca el esquinero y superviviente palacio del siglo XVI de los Gurrea de Castro. Fuente visual: Juan Mora Insa, Archivo Municipal de Zaragoza.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65362100, -0.87391600, '0101000020E6100000B56FEEAF1EF7EBBF4A7D59DAA9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25052731130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25052731130.webp', 'https://www.flickr.com/photos/zaragozaantigua/25052731130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21644, 'Fray Luis Amigâ”œâ”‚ 1921', 'Imagen capturada en la casa-reformatorio del Buen Pastor establecida desde 1917 en Torre-Ramona, con un posado de la comunidad de religiosos Terciaros capuchinos de Nâ”¬Â¬ Sâ”¬Â¬ de la Soledad encargada de administrar esta instituciâ”œâ”‚n. Entre los posantes destaca la figura de Fray Luis Amigâ”œâ”‚ (nacido como Josâ”œÂ® Marâ”œÂ¡a Amigâ”œâ”‚ Ferrer), el segundo sentado desde la izquierda, fundador de la congregaciâ”œâ”‚n en 1889 y obispo desde 1907, durante una visita a sus hermanos. Una derivada de su apellido hizo que popularmente se conociera a esta congregaciâ”œâ”‚n como "amigonianos".', 1921, 1921, 1921, 'Anos 20', 'LAS FUENTES', 41.64205800, -0.86345600, '0101000020E6100000861E317A6EA1EBBF4D11E0F42ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51246815274.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51246815274.webp', 'https://www.flickr.com/photos/zaragozaantigua/51246815274/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22900, 'Felipe Gonzâ”œÃ­lez 1983', 'Foto: EFE. Felipe Gonzâ”œÃ­lez, presidente del gobierno espaâ”œâ–’ol entre 1982 y 1996, inaugura la 17â”¬Â¬ ediciâ”œâ”‚n de la FIMA (Feria Internacional de Maquinaria Agrâ”œÂ¡cola) en la Feria de Muestras de Zaragoza. A la izquierda, Josâ”œÂ® Luis Martâ”œÂ¡nez Candial, entonces presidente de la Câ”œÃ­mara de Comercio e Industria de Zaragoza y despuâ”œÂ®s de Ibercaja. Fuente: Ayuntamiento de Valladolid.', 1983, 1983, 1983, 'Anos 80', 'UNIVERSIDAD', 41.63759000, -0.89959300, '0101000020E6100000A5BC564277C9ECBFDA20938C9CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21246408275.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21246408275.webp', 'https://www.flickr.com/photos/zaragozaantigua/21246408275/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22177, 'Calle del Asalto 1951', 'Despejada imagen de la parte final de la calle de Asalto capturada desde el principio de la calle de Monreal, con el irregular tramo donde desembocan en ella, por la derecha, las calle de la Rebolerâ”œÂ¡a, y la de Alonso V. A la izquierda, olmos (posiblemente) junto a la acequia que proveâ”œÂ¡a de agua a los talleres y fâ”œÃ­bricas textiles ubicadas en esta zona, recuerdo de cuando siglos atrâ”œÃ­s esta era la "rebolerâ”œÂ¡a" de la ciudad, donde se trataban y curtâ”œÂ¡an pieles; de esta acequia se derivaba, poco despuâ”œÂ®s. un riego que todavâ”œÂ¡a era denominado "de los Curtidores". A continuaciâ”œâ”‚n de los â”œÃ­rboles, el ingreso al cuartel de Remonta y de Sementales del Ejâ”œÂ®rcito y, al fondo, la antigua y gran torre de Juan Faustino Bruil y Olliarburu, luego de Monserrat, y que en 1965 serâ”œÂ¡a parque Bruil. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65197000, -0.86989200, '0101000020E61000003FAA61BF27D6EBBF8FFCC1C073D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31583846812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31583846812.webp', 'https://www.flickr.com/photos/zaragozaantigua/31583846812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
