INSERT INTO public.photos VALUES (22279, 'Universidad de la Magdalena 1968', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 05/09/1968. Derribo de la antigua Universidad de la Magdalena. Imagen tomada desde la Plaza de la Magdalena. A la derecha, el Coso Bajo. "Hay que rendirse a la evidencia, no se podâ”œÂ¡a evitar la demoliciâ”œâ”‚n de un edificio como â”œÂ®ste: un caserâ”œâ”‚n inmenso que no admitâ”œÂ¡a reformas satisfactorias y que, al desaparecer, darâ”œÃ­ paso a modernos y eficaces edificios que albergarâ”œÃ­n centros y dependencias de Enseâ”œâ–’anza Media y Primaria, construidos de acuerdo con las mâ”œÃ­s modernas directrices pedagâ”œâ”‚gicas. Y el futuro gran edificio tendrâ”œÃ­ desde luego una fachada de estilo mudâ”œÂ®jar, que harâ”œÃ­ juego con la inmediata iglesia de la Magdalena, cuya graciosa torre ha sido devuelta al mâ”œÃ­s brillante momento de su prâ”œÂ¡stino gâ”œâ”‚tico-mudâ”œÂ®jar; con lo que la plaza que se abre ante ella puede convertirse en uno de los rincones mâ”œÃ­s evocadores y bellos de Zaragoza". Ã”Ã‡Ã¶ Ramâ”œâ”‚n Salanova (ABC, 21.09.1968)', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65241600, -0.87349300, '0101000020E6100000211E8997A7F3EBBF8EB1135E82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14990204666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14990204666.webp', 'https://www.flickr.com/photos/zaragozaantigua/14990204666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
