INSERT INTO public.photos VALUES (22396, 'Calle Don Teobaldo 1968', 'Esquina de la calle de Don Teobaldo frente al Monasterio de la Resurrecciâ”œâ”‚n, tambiâ”œÂ®n llamado Real Monasterio de Comendadoras Canonesas de la Orden Militar y Pontificia del Santo Sepulcro. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65362600, -0.87258700, '0101000020E6100000A6457D923BECEBBF5CE84A04AAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22832693050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22832693050.webp', 'https://www.flickr.com/photos/zaragozaantigua/22832693050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22408, 'Universidad Magdalena 1968', 'Imagen capturada desde la plaza de la Magdalena durante el derribo de la antigua Universidad Literaria allâ”œÂ¡ ubicada. Considerada mayoritariamente un "caserâ”œâ”‚n inmenso que no admitâ”œÂ¡a reformas satisfactorias", estrangulaba ademâ”œÃ­s el vital trâ”œÃ­fico rodado del Coso Bajo, pues cuando fue construida no se tuvo la previsiâ”œâ”‚n de pensar en â”œÂ®l. En primer plano, montoneras de piedras y cascotes de ladrillos producto del derribo. Al frente, la "Capilla de Cerbuna", sede de la Biblioteca universitaria, mantenida en pie y declarada Monumento Histâ”œâ”‚rico-Artâ”œÂ¡stico (Decreto de 13 de marzo de 1969), aunque cuatro aâ”œâ–’os despuâ”œÂ®s se hundirâ”œÃ­ como resultado de no haber realizado ninguna obra de consolidaciâ”œâ”‚n y/o protecciâ”œâ”‚n efectiva del edificio que, aislado de las construcciones que le arropaban, terminâ”œâ”‚ cayâ”œÂ®ndose "solo". A la derecha, el Coso Bajo. Sic transit gloria Urbis. Fuente visual: Joaquâ”œÂ¡n Gil Marraco (Catâ”œÃ­logo Exposiciâ”œâ”‚n grupo "Calle a Calle", Colegio de Arquitectos de Zaragoza, abril/mayo de 1980). Amable aportaciâ”œâ”‚n de Josâ”œÂ® Luis Cintora.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65249500, -0.87271600, '0101000020E61000001C45D61A4AEDEBBFDAE6C6F484D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24558378586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24558378586.webp', 'https://www.flickr.com/photos/zaragozaantigua/24558378586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22613, 'Capilla de Cerbuna 1973', 'Foto Monge, 1973. El domingo 6 de mayo de 1973, por la tarde, se hundiâ”œâ”‚ la Capilla Pedro Cerbuna de la antigua Universidad de Zaragoza. Era el â”œâ•‘nico vestigio que quedaba en pie. Este monumento Histâ”œâ”‚rico Artâ”œÂ¡stico dejâ”œâ”‚ sus escombros sobre el patio del colegio anexo (Colegio nacional Nuestra Seâ”œâ–’ora de La Magdalena), hoy instituto. En la imagen, tomada desde el Coso Bajo, la torre de la Magdalena a la izquierda. Fuente: Diario Amanecer, 8 de mayo de 1973.', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65240800, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF0BD3F71A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19190968590.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19190968590.webp', 'https://www.flickr.com/photos/zaragozaantigua/19190968590/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22614, 'Capilla de Cerbuna 1973', 'Foto Monge, 1973. El domingo 6 de mayo de 1973, por la tarde, se hundiâ”œâ”‚ la Capilla Pedro Cerbuna de la antigua Universidad de Zaragoza. Era el â”œâ•‘nico vestigio que quedaba en pie. Este monumento Histâ”œâ”‚rico Artâ”œÂ¡stico dejâ”œâ”‚ sus escombros sobre el patio del colegio anexo (Colegio nacional Nuestra Seâ”œâ–’ora de la Magdalena), hoy instituto. La imagen estâ”œÃ­ tomada desde el Coso Bajo. Fuente: Diario Amanecer, 8 de mayo de 1973.', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65240800, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF0BD3F71A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19191178720.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19191178720.webp', 'https://www.flickr.com/photos/zaragozaantigua/19191178720/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22673, 'Capilla Cerbuna 1973', 'Imagen de la antigua Capilla Pedro Cerbuna de la Universidad de Zaragoza, tras su derrumbe por dejaciâ”œâ”‚n institucional, como reflejo de la abrumadoramente mayoritaria opiniâ”œâ”‚n de que eran meras viejas piedras que no pegaban con la moderna ciudad del momento. La imagen estâ”œÃ­ capturada desde el Coso Bajo, ya desahogado de las apreturas que los muros de la vieja Universidad le suponâ”œÂ¡an, pues originaban unas estrecheces a la "circulaciâ”œâ”‚n", que clamaban al cielo. Al poco tiempo, todo fue terminado de derribar, y todos, tan contentos. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65249500, -0.87271600, '0101000020E61000001C45D61A4AEDEBBFDAE6C6F484D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24191131276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24191131276.webp', 'https://www.flickr.com/photos/zaragozaantigua/24191131276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22713, 'Calle de Olleta 1979', 'Imagen capturada en la calle de Jusepillo de Olleta y centrada en el tramo de los pares entre las calles de Alcober y de Luzâ”œÃ­n, donde destacaba el antiguo nâ”œâ•‘mero 12, un inmueble de tres alturas representativo de la arquitectura tradicional en esta zona de la ciudad. A la derecha, vista parcial del antiguo nâ”¬â•‘ 10. Aâ”œâ–’os mâ”œÃ­s tarde, casi todos los edificios de este lado de la calle serâ”œÂ¡an derribados, y sobre ellos se construirâ”œÂ¡an modernos inmuebles, algunos ya en la segunda dâ”œÂ®cada del siglo XXI. A la izquierda, el bajo y esquinero nâ”¬â•‘ 10 de la calle de Luzâ”œÃ­n, que perdura rehabilitado, y despuâ”œÂ®s el nâ”¬â•‘ 15 de la calle de Olleta, derribado luego. Fuente visual: AMZ.', 1979, 1979, 1979, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65227400, -0.87181300, '0101000020E6100000E4486760E4E5EBBFFB03E5B67DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29281975518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29281975518.webp', 'https://www.flickr.com/photos/zaragozaantigua/29281975518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22781, 'Pl. de Asso 1979', 'Imagen capturada en la plaza de Ignacio Jordâ”œÃ­n de Asso y centrada en la antigua casa del siglo XVI que desde el siglo XVII era de la familia La Balsa, en el siglo XVIII de los La Balsa-Campi (marquesado del Palacio) para terminar recayendo en los Asso. La importancia de este edificio, aun en un entorno donde se ubicaban otras significadas casas de infanzones y nobles, determinâ”œâ”‚ la sucesiva denominaciâ”œâ”‚n de este recoleto espacio urbano: plaza de La Balsa, de Campi, y de Asso. De esta casa, tras varias modificaciones e intervenciones (la mâ”œÃ­s reciente aâ”œâ•‘n en curso) perdura, grosso modo, la traza de la fachada principal. A la izquierda, acceso a la calle de Gavâ”œÂ¡n y a la derecha, a la calle de Torrellas. Fuente visual: AMZ.', 1979, 1979, 1979, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65317200, -0.87391600, '0101000020E6100000B56FEEAF1EF7EBBFDA54DD239BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37748363585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37748363585.webp', 'https://www.flickr.com/photos/zaragozaantigua/37748363585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22852, 'Torre de La Magdalena c.1987', 'Vista desde el edificio de la calle Pelegrâ”œÂ¡n 3 de la torre mudâ”œÂ®jar de la iglesia de Santa Marâ”œÂ¡a Magdalena de Zaragoza. Al fondo, el Pilar.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65246600, -0.87406100, '0101000020E610000096B036C64EF8EBBF3FE0810184D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15259848878.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15259848878.webp', 'https://www.flickr.com/photos/zaragozaantigua/15259848878/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22862, 'Barrio de la Magdalena 1987', 'Luis Mâ”œÂ¡nguez. 1987. Desde la torre de la iglesia de la Magdalena, una mirada hacia el suroeste, siguiendo la calle de las Cortesâ”œÂ¡as, que tras llegar a San Lorenzo, se denomina de los Estudios, hasta llegar a San Jorge y toparse con la Iglesia del Real Seminario de San Carlos Borromeo, que fue la Sinagoga mayor hasta que los jesuitas le echaron el ojo. Luego, tras cruzar el Coso, la calle Espartero conduce hasta la plaza de San Miguel, donde la antigua puerta del Duque de la Victoria, se cruza el Huerva por el puente de San Josâ”œÂ®, y la bruma ya no nos deja ver mucho mâ”œÃ­s, aunque al fondo sobresale la Plana de Zaragoza. A la izquierda, en primerâ”œÂ¡simo plano, una rara visual aâ”œÂ®rea de la plazuela de la calle San Cristâ”œâ”‚bal, con coche aparcado, por supuesto.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65246600, -0.87406100, '0101000020E610000096B036C64EF8EBBF3FE0810184D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15658335797.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15658335797.webp', 'https://www.flickr.com/photos/zaragozaantigua/15658335797/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22874, 'Calle Mayor 1987', 'Luis Mâ”œÂ¡nguez. 1987. Desde la torre de la iglesia de la Magdalena, un vistazo siguiendo el decumano mâ”œÃ­ximo en direcciâ”œâ”‚n oeste, o calle Mayor hacia la avenida de Câ”œÂ®sar Augusto, donde la puerta de Toledo recordaba el cierre del perâ”œÂ¡metro amurallado de la ciudad romana. Sobre un panorama de tejados y cubiertas, en primer plano, el cruce con la trinchera de San Vicente de Paâ”œâ•‘l, cuya apertura en los primeros aâ”œâ–’os 30 del s. XX transformâ”œâ”‚ profundamente esta parte del Casco Histâ”œâ”‚rico. En lâ”œÂ¡nea recta, mâ”œÃ­s o menos, la visual llega hasta la curva del râ”œÂ¡o donde se levanta el puente de la Almozara. Hacia la derecha, agrupados, los remates del Torreâ”œâ”‚n de la Zuda, y el cimborrio y la torrecilla de San Juan de los Panetes. Hacia la izquierda, el blanco remate bulboso del chaflâ”œÃ­n con Don Jaime I, de Francisco Albiâ”œâ–’ana. Luego, la câ”œâ•‘pula y torres de Santa Isabel-San Cayetano. Casi al fondo, la mole habitacional de la plaza de Santo Domingo, junto a la torre de San Pablo. La mole estâ”œÃ­ bastante mâ”œÃ­s lejos, pero su tamaâ”œâ–’o parece acercarla. A la izquierda mâ”œÃ­s extrema, la reciente torre "nueva" derecha de la iglesia de Santiago.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65246600, -0.87406100, '0101000020E610000096B036C64EF8EBBF3FE0810184D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15843975905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15843975905.webp', 'https://www.flickr.com/photos/zaragozaantigua/15843975905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21233, 'Calle de Alfonso I 1908', 'Vista desde cierta altura de la calle de Alfonso I.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65309800, -0.88208100, '0101000020E61000000589EDEE013AECBFA08A1BB798D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19415078758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19415078758.webp', 'https://www.flickr.com/photos/zaragozaantigua/19415078758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22947, 'Calle de Alonso V 1987', 'Imagen capturada en la calle de Alonso V y centrada en uno de los antiguos torreones del recinto defensivo medieval en ladrillo de la ciudad allâ”œÂ¡ ubicados, que desde principios del siglo XVII habâ”œÂ¡an sido adaptados para vivienda, al igual que los compases entre torreones. El de la imagen se corresponde con el cuarto torreâ”œâ”‚n desde la puerta de la Portaza (luego del Sol, a la derecha, fuera de plano) y ya cercano al gran complejo del convento de San Agustâ”œÂ¡n. La vivienda allâ”œÂ¡ habilitada tenâ”œÂ¡a adjudicado el nâ”œâ•‘mero 44 (luego 26) de la calle Alonso V, con traseras a la calle de las Arcadas. Una intervenciâ”œâ”‚n municipal posterior supuso la restauraciâ”œâ”‚n y rehabilitaciâ”œâ”‚n (previo derribo de las viviendas adosadas de finales del siglo XIX) de este y otros dos torreones, ademâ”œÃ­s de algunos inmediatos lienzos del tramo de muralla. Fuente visual: AMZ.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65207400, -0.87101900, '0101000020E61000005C3AE63C63DFEBBF34492C2977D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38603459816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38603459816.webp', 'https://www.flickr.com/photos/zaragozaantigua/38603459816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22955, 'Calle de Alonso V 1987', 'Imagen capturada en la calle de Alonso V y centrada en uno de los antiguos torreones del recinto defensivo medieval en ladrillo de la ciudad, que desde el siglo XVII habâ”œÂ¡an sido adaptados para vivienda, al igual que en los compases entre los torreones se adosaron pequeâ”œâ–’as viviendas recayentes tanto a esta como a la trasera calle de las Arcadas. El de la imagen se corresponde con el cuarto torreâ”œâ”‚n desde la puerta de la Portaza, luego del Sol, que quedaba a la derecha, fuera de plano. La vivienda allâ”œÂ¡ habilitada tenâ”œÂ¡a adjudicado el nâ”œâ•‘mero 26 (antiguo 44) de la calle de Alonso V. A la derecha, el adosado inmueble del nâ”¬â•‘ 24 (antiguo 42), y a la izquierda restos del antiguo inmueble del nâ”¬â•‘ 46, ya cercano al gran complejo del convento de San Agustâ”œÂ¡n. Al fondo y a la izquierda, solana sobre las traseras del inmueble del nâ”¬â•‘ 13 de la calle de Barrioverde. En el momento de tomar esta fotografâ”œÂ¡a se estaba procediendo a urbanizar la calle. Una intervenciâ”œâ”‚n municipal posterior supuso la restauraciâ”œâ”‚n y rehabilitaciâ”œâ”‚n (previo derribo de las viviendas adosadas de finales del siglo XIX) de este y otros dos torreones, ademâ”œÃ­s de algunos inmediatos lienzos del tramo de muralla medieval.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65205600, -0.87085900, '0101000020E610000026AC8DB113DEEBBF8E942D9276D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48104213632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48104213632.webp', 'https://www.flickr.com/photos/zaragozaantigua/48104213632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22959, 'Calle de Martâ”œÂ¡n Carrillo c.1981', 'Imagen capturada en el despejado entorno de calle de Martâ”œÂ¡n Carrillo con el casi irreconocible aspecto de esta zona del barrio de la Magdalena tras los derribos de algunas de las antiguas casonas que tradicionalmente la caracterizaban, como la Casa de Tejada, que se levantaba en el inmediato solar de primer tâ”œÂ®rmino, y que a principios de los aâ”œâ–’os 90 del pasado siglo XX verâ”œÂ¡a construirse aquâ”œÂ¡ unos apreciables inmuebles seriados que desde la plaza de Asso llegan hasta las calles de Torrellas y de la Universidad. A la izquierda, leve vista del renegrido muro de la iglesia parroquial de Santa Marâ”œÂ¡a Magdalena y del inmueble esquinero con la calle del â”œÃ´rgano, tambiâ”œÂ®n construido sobre otra solariega casona de cuyo nombre no quiero acordarme. En el centro y hacia el fondo, irrepetible vista del inmueble del nâ”¬â•‘ 21 de la calle de Don Juan de Aragâ”œâ”‚n, recayente a la plazoleta que se abre en la confluencia con la calle de Pedro Liâ”œâ–’â”œÃ­n, visible temporalmente tras el derribo de la antigua casa que desde allâ”œÂ¡ llegaba hasta la plaza de Ignacio Jordâ”œÃ­n Asso, y desde 1983 sustituida por el actual inmueble del nâ”¬â•‘ 2-4 de la calle de Pedro Liâ”œâ–’â”œÃ­n. Al fondo se destaca la torre de la Seo y el remate de la torre de Santa Leonor del templo del Pilar.', 1981, 1981, 1981, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65269700, -0.87387400, '0101000020E6100000FA635A9BC6F6EBBF429946938BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52123834300.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52123834300.webp', 'https://www.flickr.com/photos/zaragozaantigua/52123834300/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23022, 'Plaza de Asso 1997', 'Imagen capturada en la plaza de Ignacio Jordâ”œÃ­n de Asso y centrada en el antiguo inmueble del nâ”¬â•‘ 28 (antes nâ”¬â•‘ 36) de la calle de Juan de Aragâ”œâ”‚n, una casona tâ”œÂ¡pica del siglo XVII de un modelo seriado bastante comâ”œâ•‘n en el antiguo barrio de La Seo, y que aquâ”œÂ¡ se muestra en muy precaria situaciâ”œâ”‚n. Aparece flanqueada por modernos edificios de viviendas (a la derecha, el sesentero nâ”¬â•‘ 4 de la vecina calle de Torrejâ”œâ”‚n; a la izquierda, el tardochentero nâ”¬â•‘ 1 de la plaza de Asso). Aâ”œâ–’os despuâ”œÂ®s esta casa fue derribada, perdurando todavâ”œÂ¡a el solar dejado. Esta imagen fue posible por el derribo, en los aâ”œâ–’os setenta, de la antigua gran casa del nâ”¬â•‘ 1 de la plaza de Asso que confrontaba con ella, y cuyo solar sirviâ”œâ”‚ para ampliar notablemente la antigua y recoleta plaza.', 1997, 1997, 1997, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65298600, -0.87418500, '0101000020E61000009AEB34D252F9EBBF785F950B95D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49352382846.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49352382846.webp', 'https://www.flickr.com/photos/zaragozaantigua/49352382846/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23074, 'Vista Sureste 2009', 'Foto Javier Peâ”œâ–’a, diciembre 2009. Vista de Zaragoza hacia el Sureste, desde la torre de la Seo. La imagen la preside la torre de La Magdalena. Fuente: www.facebook.com/photo.php?fbid=1012283675454144&set=...', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65244800, -0.87403700, '0101000020E610000074CE4F711CF8EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15304358694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15304358694.webp', 'https://www.flickr.com/photos/zaragozaantigua/15304358694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23120, 'Coso Bajo 2006', 'Vista del veterano solar esquinero del Coso Bajo (nâ”œâ•‘mero 164) con la calle del Doctor Palomar (izquierda). Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65182800, -0.87327500, '0101000020E6100000C442AD69DEF1EBBFFD4E93196FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31106504104.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31106504104.webp', 'https://www.flickr.com/photos/zaragozaantigua/31106504104/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23236, 'Casa Edad de Hierro', 'Vista general de una casa en la I Edad de Hierro (750-500 antes de nuestra Era), en la actual calle Palafox nâ”¬â•‘ 26. Fuente visual: Historia de cuatro ciudades, 2001.', NULL, NULL, NULL, NULL, 'CASCO HISTâ”œÃ´RICO', 41.65339000, -0.87333800, '0101000020E61000005C548B8862F2EBBF48C49448A2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14969299326.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14969299326.webp', 'https://www.flickr.com/photos/zaragozaantigua/14969299326/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23471, 'Calle del â”œÃ´rgano c.1935', 'Imagen de la puerta de acceso al antiguo nâ”¬â•‘ 3 de la calle del â”œÃ´rgano, sobre la que destaca el dieciochesco blasâ”œâ”‚n de la familia de los Sanez (sic) de Villa Nueva (Lanes de Villanueva). Esta casona, esquinera con la calle de Carrillo (a la derecha, fuera de plano), y frente a las traseras de la iglesia parroquial de la Magdalena, fue luego derribada al principio de los aâ”œâ–’os 40, y levantado sobre su solar un edificio de nueva planta. La piedra armera con el escudo perdura en el Museo de Zaragoza. Fuente visual: Archivo Josâ”œÂ® Galiay, AHPZ.', 1935, 1935, 1935, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65273900, -0.87398000, '0101000020E61000006475ABE7A4F7EBBF70E998F38CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31458861225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31458861225.webp', 'https://www.flickr.com/photos/zaragozaantigua/31458861225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23534, 'Universidad Magdalena 1932', 'Fotografâ”œÂ¡a Martâ”œÂ¡n Chivite. Heraldo de Aragâ”œâ”‚n. 10-05-1932. El Debate parlamentario sobre el Estatuto de Cataluâ”œâ–’a pronto se extendiâ”œâ”‚ a un agrio debate paralelo en los periâ”œâ”‚dicos, especialmente entre la prensa mâ”œÃ­s reaccionaria. En la calle, los elementos de la derecha mâ”œÃ­s extrema, provocaron graves sucesos, como este de Zaragoza que saltâ”œâ”‚ a la prensa estatal. En la Plaza de la Magdalena, entonces sede del Rectorado y las Facultades de Derecho y de Filosofâ”œÂ¡a y Letras de la Universidad, estudiantes contrarios al debate del Estatuto, desempedraron adoquines del firme, los introdujeron al interior de la Universidad, y se hicieron fuertes dentro. Avisados los Guardias de Asalto, fueron exhortaron a que depusieran su actitud, a lo que respondieron lanzando adoquines, uno de los cuales impactâ”œâ”‚ sobre un Teniente, causâ”œÃ­ndole heridas graves. Ademâ”œÃ­s, en los altercados que siguieron, con intercambio de disparos de bala incluido, resultaron heridos un par de estudiantes, y un Cabo. La Guardia de Asalto entrâ”œâ”‚ en el recinto, detuvo a 60 estudiantes, y cesaron los disturbios. Al lugar acudieron el Gobernador, el presidente de la Audiencia Territorial, y un juez instructor. La Junta de Gobierno de la Universidad lamentâ”œâ”‚ lo sucedido, censurâ”œâ”‚ el proceder de los causantes de los desâ”œâ”‚rdenes, aplicâ”œâ”‚ el Reglamento de disciplina escolar a los escolares menores de edad implicados, y abriâ”œâ”‚ un expediente para depurar responsabilidades. Ademâ”œÃ­s, la Universidad fue clausurada dos dâ”œÂ¡as. Fuente: ABC Madrid. En la imagen, publicada en prensa despuâ”œÂ®s de los hechos, algunos de los estudiantes detenidos en el momento de abandonar el edificio de la Universidad de la Magdalena. Adoquines implicados, en el suelo.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65208000, -0.87328900, '0101000020E6100000029CDEC5FBF1EBBF1630815B77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14666083288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14666083288.webp', 'https://www.flickr.com/photos/zaragozaantigua/14666083288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
