INSERT INTO public.photos VALUES (23538, 'Pl. de la Magdalena 1677', 'Entrada de Carlos II en Zaragoza. Dibujo, 1910. El 1 de mayo de 1677 el rey Carlos II jurâ”œâ”‚ los Fueros de Aragâ”œâ”‚n en la Seo de Zaragoza, y el 14 daban comienzo, en presencia del monarca, las Cortes del Reino. Las Cortes se celebraron finalmente en Zaragoza, y no en Calatayud, como estaba previsto inicialmente. El rey permaneciâ”œâ”‚ en la capital aragonesa hasta el 2 de junio. Fuente: reinadodecarlosii.blogspot.com.es/2012/03/las-relaciones-...', 1677, 1677, 1677, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15033442500.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15033442500.webp', 'https://www.flickr.com/photos/zaragozaantigua/15033442500/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23541, 'Puerta del Sol 1749', '"Puerta del Sol", Antonio Callaved, 2011. Esta puerta cerraba la ciudad al final del actual Coso Bajo, junto a las Tenerâ”œÂ¡as. Fue construida en 1749 y derribada en el siglo XIX. La piedra con un sol tallado que la coronaba se conserva en el Museo de Zaragoza. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1749, 1749, 1749, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65335400, -0.87184100, '0101000020E610000061FBC9181FE6EBBFFB5A971AA1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15092631837.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15092631837.webp', 'https://www.flickr.com/photos/zaragozaantigua/15092631837/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23542, 'Incendio discoteca Flying 1990', 'Foto Eduardo Bayona/El Periâ”œâ”‚dico de Aragâ”œâ”‚n. La madrugada del domingo 14 de enero de 1990 se produjo un incendio en la discoteca Flying, sita en la esquina de la calle Trinidad con Don Teobaldo. Murieron 43 personas. En la imagen podemos ver varios de los cadâ”œÃ­veres depositados en el exterior de la sala, en la calle Trinidad.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65333800, -0.87267200, '0101000020E6100000335184D4EDECEBBFF59D5F94A0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15161776125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15161776125.webp', 'https://www.flickr.com/photos/zaragozaantigua/15161776125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23544, 'Pl. de San Agustâ”œÂ¡n 1964', 'Celebracioes festivas en la plaza de San Agustâ”œÂ¡n en 1964. Fuente: www.facebook.com/photo.php?fbid=385217108301791&set=o...', 1964, 1964, 1964, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65090800, -0.87080100, '0101000020E6100000FF5E0A0F9ADDEBBF365A0EF450D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15738315929.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15738315929.webp', 'https://www.flickr.com/photos/zaragozaantigua/15738315929/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23545, 'Calle de la Universidad 1954', 'Chiquillerâ”œÂ¡a jugando entre claroscuros en la calle de la Universidad. Una canciâ”œâ”‚n infantil parece escucharse entre risas: Al corro de la patata, comeremos ensalada, como comen los seâ”œâ–’ores, naranjitas y limones... Al fondo, la plaza de la Magdalena, y a la izquierda e inmediata, la calle de la Trinidad. Este entorno, luego desaparecido, sâ”œâ”‚lo perdura ya en la memoria, como sucede con el que fuera trenque de la muralla de piedra, la plaza del Estudio, y los colegios de San Vicente Ferrer, de la Trinidad y de San Juan Bautista de los Navarros. Y por supuesto el edificio de la vieja Universidad, entre las puertas de Valencia y del Sol. En la solana de la imagen, entrada del viejo Instituto Goya, denominaciâ”œâ”‚n desde 1933 del anterior Instituto de Segunda Enseâ”œâ–’anza de la Magdalena. Fuente visual: Foto Pomarâ”œâ”‚n.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65329800, -0.87267200, '0101000020E6100000335184D4EDECEBBF6745D4449FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16166489434.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16166489434.webp', 'https://www.flickr.com/photos/zaragozaantigua/16166489434/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23546, 'Las Tenerâ”œÂ¡as 1591', 'F. Mota es el nombre con el que firmaba sus trabajos el pintor Fernando Fernâ”œÃ­ndez Mota, ilustrador de publicaciones entre finales del XIX y principios del XX. En este caso, se trata de otro interesante ejercicio de reinvenciâ”œâ”‚n histâ”œâ”‚rica propio del nacionalismo româ”œÃ­ntico decimonâ”œâ”‚nico, aquâ”œÂ¡ centrado en los extraâ”œâ–’os sucesos y alteraciones del verano de 1591. Esta imagen es muestra de los desvarâ”œÂ¡os que dichas alteraciones produjeron en el imaginario româ”œÃ­ntico-conservador. Tomando una reciente fotografâ”œÂ¡a del francâ”œÂ®s Jean Laurent de un pedazo del lienzo de las murallas medievales de las Tenerâ”œÂ¡as, este pintor ceutâ”œÂ¡ F. Mota agrega unos desorientados soldados que parecen sacados de una expediciâ”œâ”‚n del extremeâ”œâ–’o Pizarro al otro lado del charco, y construye una representaciâ”œâ”‚n considerada "pintura histâ”œâ”‚rica". Que los soldados estâ”œÃ­n desorientados, es literal: viniendo desde Utebo (como dicen las crâ”œâ”‚nicas histâ”œâ”‚ricas), en lugar de entrar por la puerta de Sancho, la del Portillo, o incluso la de Baltax, esta tropa habrâ”œÂ¡a dado la vuelta a la ciudad, hasta buscar el ingreso por la Portaza. Mientras tanto, la ciudad, al fondo, esperando pacientemente a ser "conquistada". Fuente visual: Ã”Ã‡Â£Entrada de las tropas castellanas en ZaragozaÃ”Ã‡Ã˜, Fernando Fernâ”œÃ­ndez Mota, 1919.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65335400, -0.87184100, '0101000020E610000061FBC9181FE6EBBFFB5A971AA1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17666352789.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17666352789.webp', 'https://www.flickr.com/photos/zaragozaantigua/17666352789/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
